cy.fixture('users').then(({
  validUser,
  wrongPassword
}) => {
  _LogIn.default.login(validUser.username, wrongPassword.password);
  // 1 + 2: contenedor de error visible con mensaje correcto
  cy.get(_LogIn.default.errorMsg).should('be.visible').and('contain', 'Epic sadface: Username and password do not match any user in this service');
  // 3: URL no avanzó al inventario
  cy.url().should('not.include', '/inventory.html');
  // 4: formulario de login sigue visible
  cy.get(_LogIn.default.loginForm).should('be.visible');
  // 5: listado de productos no existe
  cy.get(_Inventory.default.inventoryList).should('not.exist');
  // 6: campos muestran estado visual de error
  cy.get(_LogIn.default.usernameInput).should('have.class', 'input_error');
  cy.get(_LogIn.default.passwordInput).should('have.class', 'input_error');
});

